import { useEffect, useState } from "react";
import { socket } from "./socket";

function Room({ room, userName, role }) {
  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");
  const [scores, setScores] = useState({});
  const [timeLeft, setTimeLeft] = useState(10);

  useEffect(() => {
    socket.emit("join_room", {
        roomCode: room,
        role,
        name: userName,
    });

    socket.on("receive_question", (q) => {
      setQuestion(q);
    });

    socket.on("timer_update", (time) => {
      setTimeLeft(time);
    });

    socket.on("update_scores", (data) => {
        setScores(data);
    });

    socket.on("receive_answer", (a) => {
      console.log("Answer:", a);
    });

    socket.on("quiz_finished", (finalScores) => {
        alert("Квиз закончен!");
        console.log(finalScores);
    });

    return () => {
      socket.off("receive_question");
      socket.off("receive_answer");
    };
  }, [room]);

  const sendQuestion = () => {
    socket.emit("send_question", {
      roomCode: room,
      question: "2+2?",
      correct: "4",
    });
  };

  const sendAnswer = () => {
    if (timeLeft <= 0) return;

    socket.emit("submit_answer", {
        roomCode: room,
        answer,
        name: userName,
    });
  };


  return (
    <div>
      <label>
        <input type="checkbox" onChange={(e) => setTimerEnabled(e.target.checked)} />
        Enable timer
      </label>

      <input
        type="number"
        placeholder="Seconds"
        onChange={(e) => setTimeLimit(Number(e.target.value))}
      />

      <h2>Room: {room}</h2>

      <button onClick={sendQuestion}>
        Отправить вопрос (организатор)
      </button>

      {question && (
        <div>
            {question.imageUrl && (
            <img src={question.imageUrl} alt="" width="200" />
            )}

            <h3>{question.text}</h3>

            {question.options?.map((opt, i) => (
            <button key={i} onClick={() => setAnswer(opt)}>
                {opt}
            </button>
            ))}
        </div>
      )}

      <h3>Leaderboard:</h3>
      {Object.entries(scores).map(([user, score]) => (
        <div key={user}>
            {user}: {score}
        </div>
      ))}

      <h2>Времени осталось: {timeLeft}</h2>

      <input
        placeholder="Ваш ответ"
        onChange={(e) => setAnswer(e.target.value)}
      />

      <button onClick={sendAnswer}>
        Ответить
      </button>

      <button
        onClick={() => {
            socket.emit("start_quiz", {
                roomCode: room,
                quizId: 1,
                timerEnabled: true,
                timeLimit: 10,
            });
        }}
      >
      Старт квиза
      </button>

      {role === "organizer" && (
        <button
            onClick={() => {
                socket.emit("next_question", {
                roomCode: room,
                });
            }}
        >
            Следующий вопрос
        </button>
      )}
    </div>
  );
}

export default Room;
